import azure.functions as func
import json
import logging
from datetime import datetime

app = func.FunctionApp()

@app.function_name(name="PaymentWebhook")
@app.route(route="webhook/payment", methods=["POST"], auth_level=func.AuthLevel.ANONYMOUS)
def payment_webhook(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Payment webhook triggered')
    
    try:
        req_body = req.get_json()
        
        if not req_body:
            return func.HttpResponse(
                json.dumps({"error": "Request body is required"}),
                status_code=400,
                mimetype="application/json"
            )
        
        payment_id = req_body.get('payment_id')
        status = req_body.get('status')
        amount = req_body.get('amount')
        currency = req_body.get('currency')
        provider = req_body.get('provider')
        transaction_id = req_body.get('transaction_id')
        timestamp = req_body.get('timestamp', datetime.utcnow().isoformat())
        
        if not all([payment_id, status, amount, currency, provider]):
            return func.HttpResponse(
                json.dumps({"error": "Missing required fields: payment_id, status, amount, currency, provider"}),
                status_code=400,
                mimetype="application/json"
            )
        
        payment_data = {
            "payment_id": payment_id,
            "status": status,
            "amount": amount,
            "currency": currency,
            "provider": provider,
            "transaction_id": transaction_id,
            "timestamp": timestamp,
            "processed_at": datetime.utcnow().isoformat()
        }
        
        logging.info(f"Processing payment notification: {json.dumps(payment_data)}")
        
        process_payment_notification(payment_data)
        
        response_data = {
            "success": True,
            "message": "Payment notification processed successfully",
            "payment_id": payment_id,
            "received_at": datetime.utcnow().isoformat()
        }
        
        return func.HttpResponse(
            json.dumps(response_data),
            status_code=200,
            mimetype="application/json"
        )
        
    except ValueError as ve:
        logging.error(f"Invalid JSON in request body: {str(ve)}")
        return func.HttpResponse(
            json.dumps({"error": "Invalid JSON format"}),
            status_code=400,
            mimetype="application/json"
        )
    except Exception as e:
        logging.error(f"Error processing payment webhook: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": "Internal server error", "details": str(e)}),
            status_code=500,
            mimetype="application/json"
        )


def process_payment_notification(payment_data):
    status = payment_data.get('status', '').lower()
    
    if status == 'completed':
        handle_payment_completed(payment_data)
    elif status == 'failed':
        handle_payment_failed(payment_data)
    elif status == 'pending':
        handle_payment_pending(payment_data)
    elif status == 'refunded':
        handle_payment_refunded(payment_data)
    else:
        logging.warning(f"Unknown payment status: {status}")


def handle_payment_completed(payment_data):
    logging.info(f"Payment completed: {payment_data['payment_id']}")


def handle_payment_failed(payment_data):
    logging.warning(f"Payment failed: {payment_data['payment_id']}")


def handle_payment_pending(payment_data):
    logging.info(f"Payment pending: {payment_data['payment_id']}")


def handle_payment_refunded(payment_data):
    logging.info(f"Payment refunded: {payment_data['payment_id']}")